sql:
SELECT experiment_id 
FROM experiments 
WHERE algorithm = (SELECT algorithm_name FROM algorithms WHERE algorithm_id = 0);

SELECT tm.experiment_id, tm.total_reward
FROM total_metrics tm
WHERE tm.average_reward_per_episode = (SELECT MAX(average_reward_per_episode) FROM total_metrics);

SELECT e.experiment_name, tm.total_reward, tm.episodes
FROM experiments AS e
JOIN total_metrics AS tm ON e.experiment_id = tm.experiment_id;

SELECT AVG(rollout_duration) AS average_rollout_duration
FROM rollout_metrics
WHERE experiment_id = 1;
